import{_ as t,o as e,c as s,i as a}from"./chunks/framework.DP1yFSuu.js";const c=JSON.parse('{"title":"Utilities & Styling FAQ","description":"Common questions about utility classes, Tailwind, import order, and styling pitfalls.","frontmatter":{"title":"Utilities & Styling FAQ","description":"Common questions about utility classes, Tailwind, import order, and styling pitfalls."},"headers":[],"relativePath":"faqs/utilities-and-styling.md","filePath":"faqs/utilities-and-styling.md"}'),l={name:"faqs/utilities-and-styling.md"};function n(o,i,r,d,h,p){return e(),s("div",null,[...i[0]||(i[0]=[a(`<h1 id="utilities-styling-faq" tabindex="-1">Utilities &amp; Styling FAQ <a class="header-anchor" href="#utilities-styling-faq" aria-label="Permalink to &quot;Utilities &amp; Styling FAQ&quot;">​</a></h1><p>These questions cover how to choose between Cobalt’s utility layers, Tailwind integration, and custom CSS.</p><h2 id="should-i-use-cobalt-tokens-css-utilities-or-tailwind" tabindex="-1">Should I use <code>@cobalt/tokens/css/utilities</code> or Tailwind? <a class="header-anchor" href="#should-i-use-cobalt-tokens-css-utilities-or-tailwind" aria-label="Permalink to &quot;Should I use \`@cobalt/tokens/css/utilities\` or Tailwind?&quot;">​</a></h2><p>Choose based on the stack you already have:</p><ul><li>Use <code>@cobalt/tokens/css/utilities</code> when you want a lightweight, token-backed utility layer without Tailwind</li><li>Use the Tailwind preset when Tailwind is already part of your stack and you want standard Tailwind class names backed by Cobalt tokens</li></ul><p>If Tailwind is already established in your app, the Tailwind preset is usually the better fit.</p><h2 id="can-i-use-both-utilities-and-tailwind" tabindex="-1">Can I use both utilities and Tailwind? <a class="header-anchor" href="#can-i-use-both-utilities-and-tailwind" aria-label="Permalink to &quot;Can I use both utilities and Tailwind?&quot;">​</a></h2><p>Yes, but in most apps it is redundant.</p><p>Both layers exist to apply token-backed utility styling. Using both is reasonable during migration or in mixed environments, but for long-term app code it is usually clearer to standardize on one utility vocabulary.</p><h2 id="what-utilities-are-intentionally-not-included-in-cobalt-s-utility-stylesheet" tabindex="-1">What utilities are intentionally not included in Cobalt’s utility stylesheet? <a class="header-anchor" href="#what-utilities-are-intentionally-not-included-in-cobalt-s-utility-stylesheet" aria-label="Permalink to &quot;What utilities are intentionally not included in Cobalt’s utility stylesheet?&quot;">​</a></h2><p>The standalone Cobalt utilities do <strong>not</strong> try to replace a full layout framework.</p><p>Notably absent:</p><ul><li>display utilities</li><li>flexbox/grid layout primitives</li><li>positioning helpers</li><li>complex selector/state logic</li><li>animation authoring helpers</li></ul><p>For those needs, use Tailwind or write scoped CSS.</p><h2 id="what-import-order-is-required" tabindex="-1">What import order is required? <a class="header-anchor" href="#what-import-order-is-required" aria-label="Permalink to &quot;What import order is required?&quot;">​</a></h2><p>The safe order is:</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FF9492;--shiki-light:#D73A49;">@import</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> &#39;@cobalt/tokens/css&#39;</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">;</span></span>
<span class="line"><span style="--shiki-dark:#FF9492;--shiki-light:#D73A49;">@import</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> &#39;@cobalt/tokens/css/fonts&#39;</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">; </span><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;">/* optional */</span></span>
<span class="line"><span style="--shiki-dark:#FF9492;--shiki-light:#D73A49;">@import</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> &#39;@cobalt/tokens/css/base&#39;</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">; </span><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;">/* optional */</span></span>
<span class="line"><span style="--shiki-dark:#FF9492;--shiki-light:#D73A49;">@import</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> &#39;@cobalt/tokens/themes/default&#39;</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">; </span><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;">/* optional theme bundle */</span></span>
<span class="line"><span style="--shiki-dark:#FF9492;--shiki-light:#D73A49;">@import</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> &#39;@cobalt/tokens/css/utilities&#39;</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">; </span><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;">/* optional */</span></span></code></pre></div><p>The important rule is that <code>@cobalt/tokens/css</code> comes first so the cascade layer order and base token variables exist before later stylesheets try to use them.</p><h2 id="why-are-my-tokens-or-styles-not-applying" tabindex="-1">Why are my tokens or styles not applying? <a class="header-anchor" href="#why-are-my-tokens-or-styles-not-applying" aria-label="Permalink to &quot;Why are my tokens or styles not applying?&quot;">​</a></h2><p>Check these first:</p><ol><li><code>@cobalt/tokens/css</code> is loaded</li><li>component modules are actually imported</li><li>your theme bundle is loaded if you are expecting non-default theme behavior</li><li>your import order is not creating a different cascade-layer order</li><li>you are overriding token values, not bypassing them with hardcoded CSS</li></ol><p>If styles still look wrong, the <a href="/cobalt-design-system/foundations/css-layers.html">CSS Layers</a> and <a href="/cobalt-design-system/foundations/utilities.html">Utilities</a> pages are the best next step.</p><h2 id="when-should-i-write-custom-css-instead-of-utilities" tabindex="-1">When should I write custom CSS instead of utilities? <a class="header-anchor" href="#when-should-i-write-custom-css-instead-of-utilities" aria-label="Permalink to &quot;When should I write custom CSS instead of utilities?&quot;">​</a></h2><p>Write custom CSS when you need:</p><ul><li>component-specific selectors</li><li>pseudo-classes such as <code>:hover</code> or <code>:focus-visible</code></li><li>layout logic beyond spacing/sizing/typography helpers</li><li>one-off rules that do not justify a reusable utility class</li></ul><p>Utilities are best for applying token values quickly, not for expressing every styling concern in a product.</p><h2 id="do-i-still-need-base-styles-and-fonts-if-i-use-tailwind" tabindex="-1">Do I still need base styles and fonts if I use Tailwind? <a class="header-anchor" href="#do-i-still-need-base-styles-and-fonts-if-i-use-tailwind" aria-label="Permalink to &quot;Do I still need base styles and fonts if I use Tailwind?&quot;">​</a></h2><p>Usually yes.</p><ul><li><code>@cobalt/tokens/css</code> is still required</li><li><code>@cobalt/tokens/css/fonts</code> is still useful if you want the Cobalt font stack</li><li><code>@cobalt/tokens/css/base</code> remains an opt-in reset/base layer decision</li></ul><p>Tailwind integration does not replace the core token layer.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/cobalt-design-system/foundations/utilities.html">Utility Classes</a></li><li><a href="/cobalt-design-system/foundations/tailwind.html">Tailwind Integration</a></li><li><a href="/cobalt-design-system/foundations/css-layers.html">CSS Layers</a></li><li><a href="/cobalt-design-system/getting-started/developers.html">Getting Started for Developers</a></li></ul>`,32)])])}const y=t(l,[["render",n]]);export{c as __pageData,y as default};
